+			this.readModel.onDidChange(() => {
+				this.pushSnapshot().catch((error) => {
+					this.outputChannel?.appendLine(
+						`[Orchestration] snapshot push failed: ${formatError(error)}`
+					);
+				});
+			})
+		);
+	}
