+							: session.cloudProviderId ?? "Cloud Agent"}
+					</p>
+				</div>
+				<StatePill state={session.state} />
+			</div>
+
+			<dl className="mt-3 grid grid-cols-2 gap-2 text-xs text-[var(--vscode-descriptionForeground)]">
+				<div>
+					<dt>Agent</dt>
+					<dd className="mt-0.5 text-[var(--vscode-foreground)]">{session.agentName}</dd>
