+					<dt>Target</dt>
+					<dd className="mt-0.5 text-[var(--vscode-foreground)]">
+						{session.executionTargetLabel ?? "Unknown"}
+					</dd>
+				</div>
+				<div>
+					<dt>Updated</dt>
