+							payload: { source: session.source },
+						})
+					}
+					type="button"
+				>
+					Open original view
+				</button>
+				{session.externalUrl ? (
+					<button
+						className="rounded-md border border-[var(--vscode-panel-border)] px-2.5 py-1.5 text-xs"
+						onClick={() =>
+							vscode.postMessage({
+								type: "orchestration/open-external",
+								payload: { url: session.externalUrl },
+							})
+						}
+						type="button"
+					>
+						Open external
+					</button>
+				) : null}
+			</div>
+		</article>
+	);
+}
+
+function StatePill({ state }: { state: string }): JSX.Element {
+	const tone =
+		state === "completed"
+			? "bg-emerald-500/20 text-emerald-200"
+			: state === "failed" || state === "cancelled" || state === "ended-by-shutdown"
+				? "bg-rose-500/20 text-rose-200"
+				: state === "waiting-for-input" || state === "blocked"
+					? "bg-amber-500/20 text-amber-200"
+					: "bg-sky-500/20 text-sky-200";
+
+	return (
+		<span className={`rounded-full px-2 py-1 text-[11px] font-medium ${tone}`}>
+			{state}
+		</span>
+	);
+}
+
+function formatTimestamp(timestamp: number): string {
+	if (!timestamp) {
+		return "Unknown";
+	}
+	return new Date(timestamp).toLocaleTimeString([], {
+		hour: "2-digit",
+		minute: "2-digit",
+	});
+}
